// ============================================
// RECOVERY ENGINE - Restore paused teasers
// ============================================
// Rules:
//   paused_low_ctr:    24h min pause -> recover with max_bid if < 7 days old, else STOP
//   paused_high_cpl:   12h min pause -> recover with max_bid (give another chance)
//   paused_budget:     auto-recover at morning (06:00) with bid * 0.9
//   paused_anomaly:    only if anomaly resolved -> recover with previous bid
//   recovery_queue:    48h timeout -> STOP permanently
//   stopped:           30 days timeout -> mark DEAD
// Max 3 recovery attempts per teaser.

const pausedTeasers = $('Fetch Paused Teasers').all().map(i => i.json);
const anomalyItems = $('Fetch Active Anomalies').all().map(i => i.json);

if (pausedTeasers.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No paused teasers to recover' } }];
}

// Anomaly map: ad_id -> has unresolved anomaly
const anomalyMap = {};
anomalyItems.forEach(a => {
  const adId = Number(a.ad_id);
  if (!anomalyMap[adId]) anomalyMap[adId] = [];
  anomalyMap[adId].push(a);
});

const now = new Date();
const hour = now.getHours();
const isMorning = hour >= 5 && hour <= 8;

const actions = [];

pausedTeasers.forEach(t => {
  const hoursInState = Number(t.hours_in_state) || 0;
  const recoveryAttempts = Number(t.recovery_attempts) || 0;
  const maxBid = Number(t.max_bid) || 0.15;
  const minBid = Number(t.min_bid) || 0.01;
  const currentBid = Number(t.bid) || minBid;
  const geo = t.country_code || '?';
  const hasUnresolvedAnomaly = (anomalyMap[t.ad_id] || []).length > 0;

  let action = 'HOLD';
  let newBid = currentBid;
  let newState = t.state;
  let reason = '';

  switch (t.state) {
    case 'paused_low_ctr':
      if (hoursInState < 24) {
        action = 'HOLD';
        reason = `${geo} #${t.ad_id} paused_low_ctr: ${hoursInState.toFixed(1)}h < 24h min`;
      } else if (recoveryAttempts >= 2) {
        // Too many attempts, stop permanently
        action = 'STOP_PERMANENT';
        newState = 'dead';
        reason = `${geo} #${t.ad_id} paused_low_ctr: ${recoveryAttempts} recovery attempts exhausted`;
      } else {
        // Give another chance with max bid to get real data
        action = 'RECOVER';
        newBid = maxBid;
        newState = 'active';
        reason = `${geo} #${t.ad_id} paused_low_ctr: recovering at max bid $${maxBid} (attempt ${recoveryAttempts + 1}/3)`;
      }
      break;

    case 'paused_high_cpl':
      if (hoursInState < 12) {
        action = 'HOLD';
        reason = `${geo} #${t.ad_id} paused_high_cpl: ${hoursInState.toFixed(1)}h < 12h min`;
      } else if (recoveryAttempts >= 2) {
        action = 'STOP_PERMANENT';
        newState = 'dead';
        reason = `${geo} #${t.ad_id} paused_high_cpl: ${recoveryAttempts} recovery attempts exhausted`;
      } else {
        // Recover with max bid - fresh start
        action = 'RECOVER';
        newBid = maxBid;
        newState = 'active';
        reason = `${geo} #${t.ad_id} paused_high_cpl: recovering at max bid $${maxBid} (attempt ${recoveryAttempts + 1}/3)`;
      }
      break;

    case 'paused_budget':
      if (!isMorning) {
        action = 'HOLD';
        reason = `${geo} #${t.ad_id} paused_budget: waiting for morning (06:00)`;
      } else {
        // Auto-recover in morning with slightly lower bid
        action = 'RECOVER';
        newBid = Math.max(currentBid * 0.9, minBid);
        newState = 'active';
        reason = `${geo} #${t.ad_id} paused_budget: morning auto-recover at $${newBid.toFixed(4)}`;
      }
      break;

    case 'paused_anomaly':
      if (hasUnresolvedAnomaly) {
        if (hoursInState > 24) {
          newState = 'stopped';
          action = 'ESCALATE';
          reason = `${geo} #${t.ad_id} paused_anomaly: unresolved >24h, escalating to stopped`;
        } else {
          action = 'HOLD';
          reason = `${geo} #${t.ad_id} paused_anomaly: anomaly still active`;
        }
      } else {
        // Anomaly resolved, recover
        action = 'RECOVER';
        newBid = currentBid;  // Same bid, anomaly was external
        newState = 'active';
        reason = `${geo} #${t.ad_id} paused_anomaly: anomaly resolved, recovering at $${currentBid.toFixed(4)}`;
      }
      break;

    case 'recovery_queue':
      if (hoursInState > 48) {
        action = 'STOP_PERMANENT';
        newState = 'stopped';
        reason = `${geo} #${t.ad_id} recovery_queue: 48h timeout, stopping`;
      } else {
        action = 'HOLD';
        reason = `${geo} #${t.ad_id} recovery_queue: ${hoursInState.toFixed(1)}h / 48h`;
      }
      break;

    case 'stopped':
      if (hoursInState > 30 * 24) {
        action = 'MARK_DEAD';
        newState = 'dead';
        reason = `${geo} #${t.ad_id} stopped: 30 days timeout, marking dead`;
      } else {
        action = 'HOLD';
        reason = `${geo} #${t.ad_id} stopped: ${(hoursInState / 24).toFixed(1)} days`;
      }
      break;
  }

  if (action !== 'HOLD') {
    actions.push({
      json: {
        teaser_id: t.teaser_id,
        ad_id: t.ad_id,
        action: action,
        old_state: t.state,
        new_state: newState,
        current_bid: currentBid,
        new_bid: Math.round(newBid * 10000) / 10000,
        recovery_attempts: recoveryAttempts,
        hours_in_state: Math.round(hoursInState * 10) / 10,
        geo: geo,
        reason: reason
      }
    });
  }
});

if (actions.length === 0) {
  return [{ json: { action: 'NONE', reason: `Checked ${pausedTeasers.length} paused teasers, none ready for recovery` } }];
}

return actions;

const items = $input.all();
const changes = items.filter(i => i.json.action && i.json.action !== 'NONE');

if (changes.length === 0) return [];

const recovered = changes.filter(i => i.json.action === 'RECOVER');
const stopped = changes.filter(i => i.json.action === 'STOP_PERMANENT' || i.json.action === 'MARK_DEAD');
const escalated = changes.filter(i => i.json.action === 'ESCALATE');

let msg = `RECOVERY ENGINE ${$now.toFormat('dd.MM.yyyy HH:mm')}\n`;
msg += `Recovered: ${recovered.length} | Stopped: ${stopped.length} | Escalated: ${escalated.length}\n\n`;

if (recovered.length > 0) {
  msg += `RECOVERED:\n`;
  recovered.forEach(r => {
    msg += `  ${r.json.geo} #${r.json.ad_id}: ${r.json.old_state} -> active, bid $${r.json.new_bid} (attempt ${r.json.recovery_attempts + 1}/3)\n`;
  });
  msg += `\n`;
}

if (stopped.length > 0) {
  msg += `PERMANENTLY STOPPED:\n`;
  stopped.forEach(s => {
    msg += `  ${s.json.geo} #${s.json.ad_id}: ${s.json.old_state} -> ${s.json.new_state} (${s.json.recovery_attempts} attempts)\n`;
  });
  msg += `\n`;
}

if (escalated.length > 0) {
  msg += `ESCALATED:\n`;
  escalated.forEach(e => {
    msg += `  ${e.json.geo} #${e.json.ad_id}: ${e.json.reason}\n`;
  });
}

return [{ json: { message: msg } }];
